const ERROR_NON_ADJ = "Cannot connect non-adjacent islands";
const ERROR_MAX2 = "Max 2 bridges per pair";
const ERROR_EXCEED = "Island would exceed its number";
const ERROR_CROSS = "Bridges would cross";

function isAligned(a, b) {
  return a.x === b.x || a.y === b.y;
}

function canonicalKey(from, to) {
  const a = { x: from.x, y: from.y };
  const b = { x: to.x, y: to.y };
  if (a.x < b.x) return `${a.x},${a.y},${b.x},${b.y}`;
  if (a.x > b.x) return `${b.x},${b.y},${a.x},${a.y}`;
  if (a.y <= b.y) return `${a.x},${a.y},${b.x},${b.y}`;
  return `${b.x},${b.y},${a.x},${a.y}`;
}

function parseKey(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function islandAt(islands, x, y) {
  return islands.find((i) => i.x === x && i.y === y) || null;
}

function isAdjacent(islands, from, to) {
  if (!from || !to) return false;
  if (from.id === to.id) return false;
  if (!isAligned(from, to)) return false;

  const dx = Math.sign(to.x - from.x);
  const dy = Math.sign(to.y - from.y);
  let cx = from.x + dx;
  let cy = from.y + dy;
  while (cx !== to.x || cy !== to.y) {
    if (islandAt(islands, cx, cy)) return false;
    cx += dx;
    cy += dy;
  }
  return true;
}

function segmentsCross(segA, segB) {
  // seg: {x1,y1,x2,y2} in grid units, axis-aligned
  const a = { ...segA };
  const b = { ...segB };
  const aH = a.y1 === a.y2;
  const bH = b.y1 === b.y2;
  if (aH === bH) return false; // parallel can't cross in interior (overlap not possible in valid game)

  const h = aH ? a : b;
  const v = aH ? b : a;

  const hxMin = Math.min(h.x1, h.x2);
  const hxMax = Math.max(h.x1, h.x2);
  const vyMin = Math.min(v.y1, v.y2);
  const vyMax = Math.max(v.y1, v.y2);

  const ix = v.x1;
  const iy = h.y1;

  // interior intersection only (not at endpoints)
  const withinH = ix > hxMin && ix < hxMax;
  const withinV = iy > vyMin && iy < vyMax;
  if (!withinH || !withinV) return false;

  return true;
}

function wouldCrossExisting(bridges, from, to) {
  const newSeg = { x1: from.x, y1: from.y, x2: to.x, y2: to.y };
  for (const [key, count] of bridges.entries()) {
    if (!count) continue;
    const seg = parseKey(key);
    // share endpoints => allowed
    const sharesEndpoint =
      (seg.x1 === newSeg.x1 && seg.y1 === newSeg.y1) ||
      (seg.x2 === newSeg.x1 && seg.y2 === newSeg.y1) ||
      (seg.x1 === newSeg.x2 && seg.y1 === newSeg.y2) ||
      (seg.x2 === newSeg.x2 && seg.y2 === newSeg.y2);
    if (sharesEndpoint) continue;

    if (segmentsCross(seg, newSeg)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islandAt(islands, x1, y1);
    const b = islandAt(islands, x2, y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!isAdjacent(islands, from, to)) {
    return { valid: false, error: ERROR_NON_ADJ };
  }

  const key = canonicalKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;

  if (next > 2) return { valid: false, error: ERROR_MAX2 };
  if (next < 0) return { valid: false, error: null };

  if (delta > 0 && wouldCrossExisting(bridges, from, to)) {
    return { valid: false, error: ERROR_CROSS };
  }

  // island counts cannot exceed value
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = (counts.get(from.id) ?? 0) + delta;
  const toCount = (counts.get(to.id) ?? 0) + delta;
  if (fromCount > from.value || toCount > to.value) {
    return { valid: false, error: ERROR_EXCEED };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islandAt(islands, x1, y1);
    const b = islandAt(islands, x2, y2);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const stack = [start];
  while (stack.length) {
    const cur = stack.pop();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        stack.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

export function isVictory(islands, bridges) {
  // no crossings
  const keys = [...bridges.entries()].filter(([, n]) => n > 0).map(([k]) => k);
  for (let i = 0; i < keys.length; i++) {
    for (let j = i + 1; j < keys.length; j++) {
      const a = parseKey(keys[i]);
      const b = parseKey(keys[j]);
      const sharesEndpoint =
        (a.x1 === b.x1 && a.y1 === b.y1) ||
        (a.x1 === b.x2 && a.y1 === b.y2) ||
        (a.x2 === b.x1 && a.y2 === b.y1) ||
        (a.x2 === b.x2 && a.y2 === b.y2);
      if (sharesEndpoint) continue;
      if (segmentsCross(a, b)) return false;
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  return checkConnectivity(islands, bridges);
}

export function getCanonicalBridgeKey(from, to) {
  return canonicalKey(from, to);
