  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValidMove() {
    if (error) setError(null);
  }

  function updateBridge(from, to, nextValue) {
    const key = getCanonicalBridgeKey(from, to);
    setBridges((prev) => {
      const m = new Map(prev);
      if (!nextValue) m.delete(key);
      else m.set(key, nextValue);
      return m;
    });
  }

  function handleToggle(from, to) {
    const key = getCanonicalBridgeKey(from, to);
    const current = bridges.get(key) ?? 0;
    const next = (current + 1) % 3; // 0->1->2->0
    if (next === 0) {
      updateBridge(from, to, 0);
      clearErrorOnValidMove();
      return;
    }

    const delta = next - current;
    const { valid, error: err } = canAddBridge(islands, bridges, from, to, delta);
    if (!valid) {
      setError(err);
      return;
    }

    updateBridge(from, to, next);
    clearErrorOnValidMove();
  }

  function handleRemoveBridge(from, to) {
    const key = getCanonicalBridgeKey(from, to);
    if ((bridges.get(key) ?? 0) === 0) return;
    updateBridge(from, to, 0);
    clearErrorOnValidMove();
  }

  function onIslandLeftClick(isl) {
    if (selectedId === null) {
      setSelectedId(isl.id);
      return;
    }

    if (selectedId === isl.id) {
      // keep selected; no toggle
      return;
    }

    const from = islands.find((i) => i.id === selectedId);
    const to = isl;
    handleToggle(from, to);
    setSelectedId(null);
  }

  function onIslandRightOrCtrlClick(e, isl) {
    e.preventDefault();
    if (selectedId !== null && selectedId !== isl.id) {
      const from = islands.find((i) => i.id === selectedId);
      handleRemoveBridge(from, isl);
      setSelectedId(null);
      return;
    }

    // if no selection, remove bridge from keyboardFrom if set, otherwise do nothing
    if (keyboardFromId !== null && keyboardFromId !== isl.id) {
      const from = islands.find((i) => i.id === keyboardFromId);
      handleRemoveBridge(from, isl);
      setKeyboardFromId(null);
    }
  }

  function moveCursor(dir) {
    if (cursorId === null) return;
    const cur = islands.find((i) => i.id === cursorId);
    if (!cur) return;

    const candidates = getAdjacentIslands(islands, cur);
    // choose based on direction by comparing coordinates
    let next = null;
    for (const c of candidates) {
      if (dir === 'ArrowLeft' && c.y === cur.y && c.x < cur.x) next = c;
      if (dir === 'ArrowRight' && c.y === cur.y && c.x > cur.x) next = c;
      if (dir === 'ArrowUp' && c.x === cur.x && c.y < cur.y) next = c;
      if (dir === 'ArrowDown' && c.x === cur.x && c.y > cur.y) next = c;
    }
    if (next) setCursorId(next.id);
  }

  useEffect(() => {
    function onKeyDown(e) {
      if (['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'].includes(e.key)) {
        e.preventDefault();
        moveCursor(e.key);
        return;
      }

      if (e.key === 'Escape') {
        e.preventDefault();
        setKeyboardFromId(null);
        setSelectedId(null);
        clearErrorOnValidMove();
        return;
      }

      if (e.key === 'Enter') {
        e.preventDefault();
        if (cursorId === null) return;
        const cur = islands.find((i) => i.id === cursorId);
        if (!cur) return;

        if (keyboardFromId === null) {
          setKeyboardFromId(cur.id);
          return;
        }

        if (keyboardFromId === cur.id) {
          // keep selection
          return;
        }

        const from = islands.find((i) => i.id === keyboardFromId);
        handleToggle(from, cur);
        setKeyboardFromId(null);
        return;
      }
    }

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [cursorId, islands, keyboardFromId, bridges, error]);

  function reset() {
    setBridges(new Map());
    setSelectedId(null);
    setKeyboardFromId(null);
    setError(null);
  }

  const bridgeLines = useMemo(() => {
    const lines = [];
    for (const [key, n] of bridges.entries()) {
      if (!n) continue;
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const a = { x: x1, y: y1 };
      const b = { x: x2, y: y2 };
      const px1 = a.x * GRID;
      const py1 = a.y * GRID;
      const px2 = b.x * GRID;
      const py2 = b.y * GRID;

      const horizontal = py1 === py2;
      const offset = 6; // px
      const dx = horizontal ? 0 : offset;
      const dy = horizontal ? offset : 0;

      const mkLine = (idx, ox, oy) => (
        <line
          key={`${key}:${idx}`}
          x1={px1 + ox}
          y1={py1 + oy}
          x2={px2 + ox}
          y2={py2 + oy}
          stroke="#0f0"
          strokeWidth={3}
        />
      );

      if (n === 1) {
        lines.push(mkLine(0, 0, 0));
      } else if (n === 2) {
        lines.push(mkLine(0, dx, dy));
        lines.push(mkLine(1, -dx, -dy));
      }
    }
    return lines;
  }, [bridges]);

  const cursorRect = useMemo(() => {
    if (cursorId === null) return null;
    const isl = islands.find((i) => i.id === cursorId);
    if (!isl) return null;
    const { cx, cy } = islandCenterPx(isl);
    const size = 34;
    const x = cx - size / 2;
    const y = cy - size / 2;
    const active = keyboardFromId === isl.id || selectedId === isl.id;
    return (
      <rect
        x={x}
        y={y}
        width={size}
        height={size}
        fill="none"
        stroke={active ? '#7CFF7C' : '#0f0'}
        strokeWidth={2}
        strokeDasharray={active ? '0' : '5 4'}
      />
    );
  }, [cursorId, islands, keyboardFromId, selectedId]);

  return (
    <div className="app-root">
      <div className="ui-bar">
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIndex}
            onChange={(e) => setPuzzleIndex(Number(e.target.value))}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>
        <button onClick={reset}>Reset</button>
        <div className="status">
          Connected: {checkConnectivity(islands, bridges) ? 'yes' : 'no'}
        </div>
      </div>

      {error ? <div className="error-message">{error}</div> : null}
      {victory ? <div className="victory-banner">SOLVED!</div> : null}

      <svg
        ref={svgRef}
        className="board"
        width={W}
        height={H}
        viewBox={`0 0 ${W} ${H}`}
        onContextMenu={(e) => e.preventDefault()}
      >
        {bridgeLines}
        {cursorRect}

        {islands.map((isl) => {
          const { cx, cy } = islandCenterPx(isl);
          const isSelected = selectedId === isl.id;
          const isKbFrom = keyboardFromId === isl.id;
          const ring = isSelected || isKbFrom;
          return (
            <g
              key={isl.id}
              transform={`translate(${cx},${cy})`}
              onClick={(e) => {
                if (isCtrlClick(e)) {
                  onIslandRightOrCtrlClick(e, isl);
                  return;
                }
                onIslandLeftClick(isl);
                setCursorId(isl.id);
              }}
              onContextMenu={(e) => onIslandRightOrCtrlClick(e, isl)}
            >
              <circle r={16} fill="black" stroke={ring ? '#7CFF7C' : '#0f0'} strokeWidth={2} />
              <text
                x={0}
                y={5}
                textAnchor="middle"
                fontSize={16}
                fill="#0f0"
              >
                {isl.value}
              </text>
              <text
                x={0}
                y={28}
                textAnchor="middle"
                fontSize={10}
                fill="#0f0"
              >
                {counts.get(isl.id) ?? 0}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

export default App;
