      (seg.x1 === newSeg.x1 && seg.y1 === newSeg.y1) ||
      (seg.x2 === newSeg.x1 && seg.y2 === newSeg.y1) ||
      (seg.x1 === newSeg.x2 && seg.y1 === newSeg.y2) ||
      (seg.x2 === newSeg.x2 && seg.y2 === newSeg.y2);
    if (sharesEndpoint) continue;

    if (segmentsCross(seg, newSeg)) return true;
  }
  return false;
}

export function computeCurrentCounts(islands, bridges) {
  const counts = new Map();
  for (const isl of islands) counts.set(isl.id, 0);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islandAt(islands, x1, y1);
    const b = islandAt(islands, x2, y2);
    if (!a || !b) continue;
    counts.set(a.id, (counts.get(a.id) ?? 0) + n);
    counts.set(b.id, (counts.get(b.id) ?? 0) + n);
  }

  return counts;
}

export function canAddBridge(islands, bridges, from, to, delta) {
  if (!isAdjacent(islands, from, to)) {
    return { valid: false, error: ERROR_NON_ADJ };
  }

  const key = canonicalKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = current + delta;

  if (next > 2) return { valid: false, error: ERROR_MAX2 };
  if (next < 0) return { valid: false, error: null };

  if (delta > 0 && wouldCrossExisting(bridges, from, to)) {
    return { valid: false, error: ERROR_CROSS };
  }

  // island counts cannot exceed value
  const counts = computeCurrentCounts(islands, bridges);
  const fromCount = (counts.get(from.id) ?? 0) + delta;
  const toCount = (counts.get(to.id) ?? 0) + delta;
  if (fromCount > from.value || toCount > to.value) {
    return { valid: false, error: ERROR_EXCEED };
  }

  return { valid: true, error: null };
}

export function checkConnectivity(islands, bridges) {
  if (islands.length === 0) return true;

  const adj = new Map();
  for (const isl of islands) adj.set(isl.id, []);

  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = parseKey(key);
    const a = islandAt(islands, x1, y1);
    const b = islandAt(islands, x2, y2);
    if (!a || !b) continue;
    adj.get(a.id).push(b.id);
    adj.get(b.id).push(a.id);
  }

  const start = islands[0].id;
  const seen = new Set([start]);
  const stack = [start];
  while (stack.length) {
    const cur = stack.pop();
    for (const nxt of adj.get(cur) || []) {
      if (!seen.has(nxt)) {
        seen.add(nxt);
        stack.push(nxt);
      }
    }
  }

  return seen.size === islands.length;
}

