  // no crossings
  const keys = [...bridges.entries()].filter(([, n]) => n > 0).map(([k]) => k);
  for (let i = 0; i < keys.length; i++) {
    for (let j = i + 1; j < keys.length; j++) {
      const a = parseKey(keys[i]);
      const b = parseKey(keys[j]);
      const sharesEndpoint =
        (a.x1 === b.x1 && a.y1 === b.y1) ||
        (a.x1 === b.x2 && a.y1 === b.y2) ||
        (a.x2 === b.x1 && a.y2 === b.y1) ||
        (a.x2 === b.x2 && a.y2 === b.y2);
