      if (segmentsCross(a, b)) return false;
    }
  }

  const counts = computeCurrentCounts(islands, bridges);
  for (const isl of islands) {
    if ((counts.get(isl.id) ?? 0) !== isl.value) return false;
  }

  return checkConnectivity(islands, bridges);
}

export function getCanonicalBridgeKey(from, to) {
  return canonicalKey(from, to);
}

export function getAdjacentIslands(islands, from) {
  // nearest visible island in each cardinal direction
  const result = [];
  const dirs = [
    { dx: 1, dy: 0 },
    { dx: -1, dy: 0 },
    { dx: 0, dy: 1 },
    { dx: 0, dy: -1 }
  ];

  for (const { dx, dy } of dirs) {
    let cx = from.x + dx;
    let cy = from.y + dy;
    while (cx >= 0 && cy >= 0 && cx <= 100 && cy <= 100) {
      const hit = islandAt(islands, cx, cy);
      if (hit) {
        result.push(hit);
        break;
      }
      cx += dx;
      cy += dy;
    }
  }
  return result;
}
